import{_ as t,o as h,c as e,a0 as i}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Website","description":"","frontmatter":{"title":"Website","sidebar_position":6},"headers":[],"relativePath":"website.md","filePath":"website.md"}'),a={name:"website.md"};function c(o,n,r,g,s,u){return h(),e("div",null,[...n[0]||(n[0]=[i('<h1 id="website" tabindex="-1">Website <a class="header-anchor" href="#website" aria-label="Permalink to &quot;Website&quot;">​</a></h1><p>Mô-đun Website trong ABNERP cho phép doanh nghiệp xây dựng và quản lý website trực tiếp từ hệ thống mà không cần kiến thức lập trình. Tích hợp sẵn với các mô-đun Bán hàng, Nội dung và Tiếp thị, mô-đun này giúp doanh nghiệp nhanh chóng thiết lập kênh bán hàng trực tuyến.</p><h2 id="quan-ly-noi-dung-website-content-management" tabindex="-1">Quản lý nội dung website (Content Management) <a class="header-anchor" href="#quan-ly-noi-dung-website-content-management" aria-label="Permalink to &quot;Quản lý nội dung website (Content Management)&quot;">​</a></h2><p>ABNERP cung cấp trình soạn thảo nội dung kéo thả trực quan, cho phép bạn tạo và chỉnh sửa trang web dễ dàng. Mọi thay đổi đều được hiển thị trực tiếp, hỗ trợ đa phương tiện như hình ảnh, video, bảng biểu. Nội dung có thể được tổ chức thành các danh mục và thẻ để dễ dàng điều hướng.</p><h2 id="trang-web-web-pages" tabindex="-1">Trang web (Web Pages) <a class="header-anchor" href="#trang-web-web-pages" aria-label="Permalink to &quot;Trang web (Web Pages)&quot;">​</a></h2><p>Bạn có thể tạo nhiều loại trang khác nhau: trang giới thiệu, trang liên hệ, trang sản phẩm, tin tức, blog, và trang đích (landing page). Mỗi trang đều có thể tối ưu hóa SEO với thẻ meta, URL thân thiện, và sơ đồ trang (sitemap) tự động. Giao diện website có thể tùy chỉnh qua theme và hỗ trợ hiển thị trên mọi thiết bị.</p><h2 id="bieu-mau-web-web-forms" tabindex="-1">Biểu mẫu web (Web Forms) <a class="header-anchor" href="#bieu-mau-web-web-forms" aria-label="Permalink to &quot;Biểu mẫu web (Web Forms)&quot;">​</a></h2><p>Biểu mẫu web cho phép thu thập thông tin từ khách truy cập: đăng ký tư vấn, yêu cầu báo giá, góp ý, hoặc đăng ký sự kiện. Dữ liệu từ biểu mẫu được tự động lưu vào cơ sở dữ liệu và có thể kích hoạt các quy trình tự động như gửi email xác nhận, tạo cơ hội bán hàng hoặc gán nhiệm vụ cho nhân viên.</p><h2 id="sidebar" tabindex="-1">Sidebar <a class="header-anchor" href="#sidebar" aria-label="Permalink to &quot;Sidebar&quot;">​</a></h2><p>Sidebar giúp hiển thị các danh mục, bài viết gần đây, quảng cáo hoặc liên kết hữu ích bên cạnh nội dung chính. Bạn có thể tùy chỉnh nội dung sidebar theo từng trang hoặc nhóm trang để tăng tương tác và điều hướng.</p><h2 id="slideshow" tabindex="-1">Slideshow <a class="header-anchor" href="#slideshow" aria-label="Permalink to &quot;Slideshow&quot;">​</a></h2><p>Slideshow là công cụ hiển thị hình ảnh hoặc nội dung quảng cáo dạng trình chiếu. Bạn có thể tạo nhiều slideshow với tốc độ chuyển động và hiệu ứng khác nhau. Slideshow thường được sử dụng trên trang chủ để giới thiệu sản phẩm nổi bật, khuyến mãi hoặc thông điệp thương hiệu.</p>',12)])])}const l=t(a,[["render",c]]);export{d as __pageData,l as default};
